import { Hono } from 'hono';
import { z, ZodError } from 'zod';

const app = new Hono();

const transferTaskSchema = z.object({
  taskId: z.string(),
  sourceTeamId: z.string(),
  targetTeamId: z.string(),
});

app.post('/transfer-task', async (c) => {
  try {
    const { taskId, sourceTeamId, targetTeamId } = transferTaskSchema.parse(await c.req.json());

    // Check if the caller is an admin of the source team
    // This is a placeholder for actual authentication and authorization logic
    const isAdminOfSourceTeam = await checkIfUserIsAdmin(c.env.TEAMS_DB, sourceTeamId, c.req.user.id);
    if (!isAdminOfSourceTeam) {
      return c.json({ error: 'Unauthorized' }, 403);
    }

    // Check if both teams exist
    const sourceTeamExists = await teamExists(c.env.TEAMS_DB, sourceTeamId);
    const targetTeamExists = await teamExists(c.env.TEAMS_DB, targetTeamId);
    if (!sourceTeamExists || !targetTeamExists) {
      return c.json({ error: 'One or both teams do not exist' }, 400);
    }

    // Transfer the task
    await transferTask(c.env.TASKS_DB, taskId, sourceTeamId, targetTeamId);

    // Emit a task.transferred event
    await emitEvent('task.transferred', { taskId, sourceTeamId, targetTeamId });

    return c.json({ message: 'Task transferred successfully' }, 200);
  } catch (error) {
    if (error instanceof ZodError) {
      return c.json({ error: error.issues }, 400);
    }
    return c.json({ error: 'Internal server error' }, 500);
  }
});

